SELECT '0' AS CHK , BL.CTKEY , CT.CTNM , BL.BOXLBLNO , BL.PBLCTDATE , BL.PRYN , BL.INSERTDATE , BL.INSERTURKEY , BL.UPDATEDATE , BL.UPDATEURKEY
